mapper.insert:
INSERT INTO INBOUNDS (
    INBOUND_NO, INBOUND_TYPE, CUSTOMER_ID, WAREHOUSE_ID,
    INBOUND_DATE, CREATED_USER_ID, REMARK
) VALUES (
    #{inboundNo}, #{inboundType}, #{customerId}, #{warehouseId},
    #{inboundDate}, #{createdUserId}, #{remark}
)

INSERT INTO INBOUND_DETAILS (
    INBOUND_ID, ITEM_ID, QUANTITY, UNIT_PRICE, TOTAL_PRICE, REMARK
) VALUES (
    #{inboundId}, #{itemId}, IFNULL(#{quantity}, 0),
    IFNULL(#{unitPrice}, 0.00), IFNULL(#{totalPrice}, 0.00), #{remark}
)
